import Foundation

/// Build-time version information. Regenerated by scripts/swift/build.sh before each build.
/// When running from source via `swift run`, these reflect the last generation time.
public enum BuildInfo {
    /// Git commit SHA (short form, 12 chars). "dev" if not set at build time.
    public static let gitCommit: String = "dev"

    /// Full git commit SHA. Empty if not set at build time.
    public static let gitCommitFull: String = ""

    /// ISO-8601 timestamp of when the build was generated.
    public static let buildTime: String = ""

    /// App version from the bundle (or "dev" if unavailable).
    public static var appVersion: String {
        Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "dev"
    }

    /// Bundle identifier of the running app.
    public static var bundleIdentifier: String {
        Bundle.main.bundleIdentifier ?? "unknown"
    }
}
